++                var_ref->header.ref_count = 0;  /* Mark as being freed by GC */
 +                list_del(&p->link);
-+                js_free_rt(rt, var_ref);
++                list_add_tail(&p->link, &rt->gc_zero_ref_count_list);
 +            }
 +            break;
          default:
              list_del(&p->link);
              list_add_tail(&p->link, &rt->gc_zero_ref_count_list);
